import React, { useState, useEffect } from 'react';
import './css_comp/seat_selection.css';
import { useNavigate } from 'react-router-dom';

export default function Seat_selection(props) {
  const { compartment } = props;
  const column = 5; // Number of columns for seat arrangement
  const [booked, setBooked] = useState([18, 19, 30]);
  const [selected, setSelected] = useState([]);
  const [currentCompartment, setCurrentCompartment] = useState(null); // Currently selected compartment

  const navigate = useNavigate();
  
  useEffect(() => {
    // Sort compartment and set initial state
    const sortedCompartment = [...compartment].sort((a, b) => b.remaining_seat - a.remaining_seat);
    setCurrentCompartment(sortedCompartment[0]);
  }, [compartment]);

  const row = currentCompartment ? Math.ceil(currentCompartment.total_seat / column) : 0;

  // Handle compartment change from select dropdown
  const handleCompartmentChange = (event) => {
    const selectedId = event.target.value;
    const chosenCompartment = compartment.find((item) => item.compartment_id === selectedId);
    setCurrentCompartment(chosenCompartment);
  };

  // Handle seat booking
  const handleBooked = (seatNumber) => {
    setSelected((prevSelected) =>
      prevSelected.includes(seatNumber) ? prevSelected.filter((s) => s !== seatNumber) : [...prevSelected, seatNumber]
    );
  };

  // Render seat arrangement
  const renderSeats = () => {
    let seatCount = 1;
    return Array.from({ length: row }, (_, rowIndex) => (
      <div id="row" key={rowIndex}>
        {Array.from({ length: column + 1 }, (_, colIndex) => {
          if (colIndex === 2) {
            return <div id="space" key={`${rowIndex}-${colIndex}`} />;
          } else {
            const seatNumber = seatCount;
            seatCount++;
            if (booked.includes(seatNumber)) {
              return <div id="seat-booked" key={seatNumber}>{seatNumber}</div>;
            } else if (selected.includes(seatNumber)) {
              return <div id="seat-selected" onClick={() => handleBooked(seatNumber)} key={seatNumber}>{seatNumber}</div>;
            } else {
              return <div id="seat" onClick={() => handleBooked(seatNumber)} key={seatNumber}>{seatNumber}</div>;
            }
          }
        })}
      </div>
    ));
  };

  return (
    <div id='select_show'>
      <div id='caution'>Choose your seat(s)** Maximum 4 seats can be booked at a time.</div>
      <hr />
      <div id='caution'><p>To know seat number(s), rest the cursor on your desired seat(s). Click on it to select or deselect.</p></div>
      
      <section className='parent'>
        <div className='left-child'>
          <h2>Select Coach</h2>
          <select value={currentCompartment?.compartment_id || ''} onChange={handleCompartmentChange} id="select-coach">
            {compartment.map((item) => (
              <option key={item.compartment_id} value={item.compartment_id}>
                {item.compartment_name} - {item.remaining_seat}
              </option>
            ))}
          </select>

          <div className="seat-status">
            <div className='available'>
              <p>Available</p>
              <div id='box'></div>
            </div>
            <div className='available' id='booked'>
              <p>Booked</p>
              <div id='box'></div>
            </div>
            <div className='available' id='selected'>
              <p>Selected</p>
              <div id='box'></div>
            </div>
          </div>

          <div className="seat-choose">{renderSeats()}</div>
        </div>

        <div className="right-child">
          <h2>Seat Details</h2>
          <div id='ticket-details'>
            <p>Class</p>
            <p>Seats</p>
            <p>Fare</p>
          </div>
          <div id='tickets'>here tickets</div>

          <div id='Total-amount'>
            <h3>Total: ৳ 0 </h3>
          </div>

          <div id='btn-purchase'>
            <button onClick={() => navigate('/passangerinfo')} id='btn-continue-purchase'>CONTINUE PURCHASE</button>
          </div>
        </div>
      </section>
    </div>
  );
}
